--
-- Table structure for table `ai_faq_knowledge`
--

DROP TABLE IF EXISTS `ai_faq_knowledge`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ai_faq_knowledge` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'FAQ ID',
  `category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '问题分类',
  `question` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '问题',
  `answer` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '答案',
  `keywords` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '关键词，用于匹配',
  `target_role` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'ALL' COMMENT '目标角色：ADMIN/MEMBER/GUEST/ALL',
  `priority` int DEFAULT '1' COMMENT '优先级1-5',
  `view_count` int DEFAULT '0' COMMENT '查看次数',
  `useful_count` int DEFAULT '0' COMMENT '点赞次数',
  `status` tinyint DEFAULT '1' COMMENT '状态：1-启用，0-禁用',
  `verified` tinyint DEFAULT '0' COMMENT '是否已验证：1-是，0-否',
  `verified_at` datetime DEFAULT NULL COMMENT '验证时间',
  `verified_by` int DEFAULT NULL COMMENT '验证人ID',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_category` (`category`),
  KEY `idx_target_role` (`target_role`),
  KEY `idx_status` (`status`),
  KEY `idx_verified` (`verified`)
) ENGINE=InnoDB AUTO_INCREMENT=24 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='FAQ知识表';
/*!40101 SET character_set_client = @saved_cs_client */;

