LOCK TABLES `ai_knowledge_base` WRITE;
/*!40000 ALTER TABLE `ai_knowledge_base` DISABLE KEYS */;
INSERT INTO `ai_knowledge_base` VALUES (2,'新闻管理','如何修改已发布的新闻？','进入\"新闻管理\"页面 → 找到目标新闻 → 点击\"编辑\"按钮 → 修改内容 → 保存更新','修改新闻,编辑新闻,新闻编辑',1,'2026-03-24 17:02:13'),(3,'新闻管理','如何删除新闻？','进入\"新闻管理\"页面 → 找到目标新闻 → 点击\"删除\"按钮 → 确认删除（注：已关联活动的新闻无法删除）','删除新闻,移除新闻',1,'2026-03-24 17:02:13'),(4,'奖项管理','如何审核成员提交的奖项申请？','进入\"奖项管理\"页面 → 点击\"待审核\"筛选 → 查看奖项详情 → 点击\"通过\"或\"拒绝\"按钮 → 填写审核意见','审核奖项,奖项审核,审批奖项,奖项申请',1,'2026-03-24 17:02:13'),(5,'奖项管理','奖项申请被拒绝后还能重新申请吗？','可以，成员可以在\"我的奖项\"页面重新提交申请','重新申请,拒绝后申请',1,'2026-03-24 17:02:13'),(6,'活动管理','如何创建新活动？','进入\"活动管理\"页面 → 点击\"创建活动\" → 填写活动名称、时间、地点 → 设置报名起止时间 → 点击保存','创建活动,新建活动,活动创建',1,'2026-03-24 17:02:13'),(7,'活动管理','如何查看活动报名情况？','进入\"活动管理\"页面 → 点击目标活动的\"查看详情\" → 在详情页查看已报名成员列表','查看报名,活动报名,报名情况',1,'2026-03-24 17:02:13'),(8,'成员管理','如何添加新成员？','新成员通过招新报名系统自动创建，或管理员在\"用户管理\"中手动添加','添加成员,新增成员',1,'2026-03-24 17:02:13'),(9,'成员管理','如何重置成员密码？','进入\"用户管理\"页面 → 找到目标用户 → 点击\"重置密码\" → 系统生成默认密码并通知用户（默认密码为123456）','重置密码,密码重置,忘记密码',1,'2026-03-24 17:02:13'),(10,'项目管理','如何审批项目申请？','进入\"项目管理\"页面 → 查看待审核项目 → 点击\"详情\"查看项目信息 → 点击\"通过\"或\"拒绝\"','审批项目,项目审批,审核项目',1,'2026-03-24 17:02:13'),(11,'项目管理','项目最多允许多少人参与？','每个项目最多20名成员，由项目负责人添加','项目人数,成员数量',1,'2026-03-24 17:02:13'),(12,'招新管理','如何处理新的招新报名？','进入\"报名管理\"页面 → 查看待处理申请 → 点击\"审核\"查看详情 → 点击\"同意\"创建账号或\"拒绝\"驳回申请','处理报名,招新审核,报名审核',1,'2026-03-24 17:02:13'),(13,'招新管理','同意报名后成员需要做什么？','系统会自动创建账号并发送通知，成员使用学号作为用户名登录，默认密码为123456','同意报名,创建账号',1,'2026-03-24 17:02:13'),(14,'账号问题','忘记密码怎么办？','联系管理员重置密码，默认密码为123456','忘记密码,密码找回,登录问题',1,'2026-03-24 17:02:13'),(15,'账号问题','账户被锁定怎么办？','联系管理员解锁账户','账户锁定,账号锁定,解锁',1,'2026-03-24 17:02:13'),(16,'通用操作','如何修改个人信息？','登录后进入\"个人中心\" -> \"个人信息\" -> 点击\"编辑\"进行修改','修改信息,编辑资料,个人信息',1,'2026-03-24 17:02:13'),(20,'游客指南','如何登录系统？','访问系统首页，点击右上角\"登录\"按钮，输入学号和密码即可登录。新成员需要管理员审核通过后才能获得账号。','登录,登录系统,如何登录',1,'2026-03-28 13:30:47'),(21,'游客指南','如何注册账号？','系统不开放自主注册。新成员需联系管理员进行招新报名，由管理员审核通过后自动创建账号。','注册,注册账号,新成员',1,'2026-03-28 13:30:47'),(23,'游客指南','如何提交问题反馈？','点击导航栏\"问题反馈\"，填写问题标题和详细内容后提交。管理员审核后会更新处理状态。','问题反馈,提交问题,反馈问题',1,'2026-03-28 13:30:47'),(25,'成员-个人信息','如何修改个人资料？','登录后点击右上角头像进入\"个人中心\"，点击\"编辑资料\"按钮进行修改，保存后生效。','修改资料,编辑资料,个人信息',1,'2026-03-28 13:30:47'),(26,'成员-个人信息','如何修改登录密码？','登录后点击右上角头像进入\"个人中心\"，点击\"修改密码\"，输入原密码和新密码后确认。','修改密码,更改密码',1,'2026-03-28 13:30:47'),(27,'成员-个人信息','个人中心有哪些功能？','个人中心提供：个人信息查看/编辑、项目管理、活动管理、奖项管理、简历管理、学习记录查看等功能入口。','个人中心,我的',1,'2026-03-28 13:30:47'),(29,'成员-活动','如何查看我报名的活动？','登录后进入\"个人中心\"，点击\"我的活动\"查看所有报名记录和处理状态。','我的活动,查看报名',1,'2026-03-28 13:30:47'),(30,'成员-活动','如何取消已报名的活动？','在\"我的活动\"页面，找到要取消的活动，点击\"取消报名\"按钮。需在报名截止前操作。','取消报名,取消活动',1,'2026-03-28 13:30:47'),(32,'成员-项目','如何查看我的项目申请记录？','登录后进入\"个人中心\"，点击\"我的项目\"查看所有项目及其审核状态。','我的项目,项目记录',1,'2026-03-28 13:30:47'),(33,'成员-项目','项目申请被拒绝后可以重新申请吗？','可以，修改项目信息后可以重新提交申请。','项目被拒,重新申请',1,'2026-03-28 13:30:47'),(35,'成员-奖项','如何查看我的获奖记录？','登录后进入\"个人中心\"，点击\"我的奖项\"查看所有获奖记录及审核状态。','我的奖项,获奖记录',1,'2026-03-28 13:30:47'),(36,'成员-奖项','奖项申请被拒绝后怎么办？','可以在\"我的奖项\"页面重新编辑信息后再次提交申请。','奖项被拒,重新申请',1,'2026-03-28 13:30:47'),(37,'成员-学习','如何开始学习签到？','点击导航\"学习中心\"，在规定时间（6:00-22:00）内点击\"开始学习\"按钮进行签到。','开始学习,签到,学习签到',1,'2026-03-28 13:30:47'),(38,'成员-学习','学习时间有什么规则？','学习时间为6:00-22:00。18:00前签到为正常，18:00-19:00为迟到，19:00后为严重迟到。22:00系统自动结束学习。','学习规则,签到规则',1,'2026-03-28 13:30:47'),(39,'成员-学习','如何签退结束学习？','在学习中心点击\"签退\"按钮结束学习。21:30前签退为正常早退，21:30后为正常签退。','签退,结束学习',1,'2026-03-28 13:30:47'),(40,'成员-学习','忘记了签到怎么办？','请在下次学习时注意签到时间，系统会自动记录。目前不支持补签。','忘记签到,补签',1,'2026-03-28 13:30:47'),(41,'成员-问题反馈','如何提交问题反馈？','点击导航\"问题反馈\"，填写问题标题和详细描述后提交。管理员处理后可在列表查看状态。','提交反馈,问题反馈,提交问题',1,'2026-03-28 13:30:47'),(42,'成员-问题反馈','如何查看我提交的问题？','在问题反馈页面可以看到所有历史反馈记录及处理状态（待确认/属实/不属实）。','查看反馈,我的反馈',1,'2026-03-28 13:30:47'),(44,'管理员-新闻管理','如何修改已发布的新闻？','在新闻列表找到目标新闻，点击\"编辑\"按钮修改内容后保存。','修改新闻,编辑新闻',1,'2026-03-28 13:30:47'),(45,'管理员-新闻管理','如何删除新闻？','在新闻列表找到目标新闻，点击\"删除\"按钮确认删除。注意：已关联活动的新闻无法删除。','删除新闻',1,'2026-03-28 13:30:47'),(46,'管理员-活动管理','如何创建新活动？','点击\"活动管理\"，点击\"创建活动\"，填写活动名称、时间、地点，设置报名起止时间后保存。','创建活动,新建活动',1,'2026-03-28 13:30:47'),(47,'管理员-活动管理','如何查看活动报名情况？','在活动列表点击\"报名管理\"按钮，可查看所有报名成员及审核状态。','查看报名,报名情况',1,'2026-03-28 13:30:47'),(48,'管理员-活动管理','如何删除活动？','在活动列表找到目标活动，点击\"删除\"按钮。注意：进行中或已结束的活动无法删除。','删除活动',1,'2026-03-28 13:30:47'),(49,'管理员-项目管理','如何审核项目申请？','在项目管理页面查看\"待审核\"状态的项目，点击\"批准\"通过或\"编辑\"查看详情后处理。','审核项目,审批项目',1,'2026-03-28 13:30:47'),(50,'管理员-项目管理','项目状态有哪几种？','项目状态分为：待审核（黄色）、已通过（绿色）、已拒绝（红色）三种。','项目状态',1,'2026-03-28 13:30:47'),(51,'管理员-奖项管理','如何审核奖项申请？','在奖项管理页面查看待审核申请，点击\"通过\"或\"拒绝\"按钮处理。','审核奖项,审批奖项',1,'2026-03-28 13:30:47'),(52,'管理员-奖项管理','奖项状态有哪几种？','奖项状态分为：待审核、已通过、已拒绝三种。','奖项状态',1,'2026-03-28 13:30:47'),(53,'管理员-成员管理','如何重置成员密码？','在成员管理页面找到目标成员，点击\"重置密码\"按钮。系统会将密码重置为默认密码123456。','重置密码,忘记密码',1,'2026-03-28 13:30:47'),(54,'管理员-招新管理','如何处理招新报名？','点击\"招新管理\"，查看待处理申请，点击\"同意\"为申请者创建账号（学号即用户名，默认密码123456），或点击\"拒绝\"驳回。','处理报名,审核报名',1,'2026-03-28 13:30:47'),(55,'管理员-学习管理','如何查看学习记录？','点击\"学习管理\"，可按日期范围和成员筛选查看学习时段记录，包括开始时间、结束时间、学习时长等。','查看学习,学习记录',1,'2026-03-28 13:30:47'),(56,'管理员-学习管理','可以统计学习数据吗？','可以，学习管理页面顶部显示总学习次数、已完成次数、总时长、平均时长等统计信息。','学习统计',1,'2026-03-28 13:30:47'),(57,'管理员-问题管理','如何处理问题反馈？','点击\"问题管理\"，以三个标签页查看（属实/不属实/待确认），点击\"查看\"可更新分类、状态和处理备注。','处理问题,审核问题',1,'2026-03-28 13:30:47'),(58,'管理员-问题管理','如何删除问题反馈？','在问题列表点击\"删除\"按钮，可移除不再需要的问题记录。','删除问题',1,'2026-03-28 13:30:47'),(59,'账号问题','忘记密码怎么办？','联系管理员重置密码，重置后默认密码为123456，首次登录后请立即修改。','忘记密码,密码找回',1,'2026-03-28 13:30:47'),(60,'账号问题','默认登录密码是什么？','新账号默认密码为123456，登录后请立即修改密码。','默认密码',1,'2026-03-28 13:30:47'),(61,'账号问题','账户被锁定怎么办？','联系管理员解锁账户。','账户锁定,账号锁定,解锁',1,'2026-03-28 13:30:47'),(62,'学习规则','学习时间段是什么？','系统学习时间为每日6:00-22:00。18:00系统会强制签退（如正在学习中）。','学习时间,时段',1,'2026-03-28 13:30:47'),(63,'学习规则','签到状态如何判定？','6:00-18:00签到为正常；18:00-19:00为迟到；19:00之后为严重迟到。','签到状态',1,'2026-03-28 13:30:47'),(64,'学习规则','签退状态如何判定？','21:30前签退为早退；21:30后签退为正常；22:00系统自动结束学习。','签退状态',1,'2026-03-28 13:30:47'),(65,'游客指南','如何登录系统？','访问系统首页，点击右上角\"登录\"按钮，输入学号和密码即可登录。新成员需要管理员审核通过后才能获得账号。','登录,登录系统,如何登录',1,'2026-04-11 10:30:11'),(66,'游客指南','如何注册账号？','系统不开放自主注册。新成员需联系管理员进行招新报名，由管理员审核通过后自动创建账号。','注册,注册账号,新成员',1,'2026-04-11 10:30:11'),(68,'游客指南','如何提交问题反馈？','点击导航栏\"问题反馈\"，填写问题标题和详细内容后提交。管理员审核后会更新处理状态。','问题反馈,提交问题,反馈问题',1,'2026-04-11 10:30:11'),(70,'成员-个人信息','如何修改个人资料？','登录后点击右上角头像进入\"个人中心\"，点击\"编辑资料\"按钮进行修改，保存后生效。','修改资料,编辑资料,个人信息',1,'2026-04-11 10:30:11'),(71,'成员-个人信息','如何修改登录密码？','登录后点击右上角头像进入\"个人中心\"，点击\"修改密码\"，输入原密码和新密码后确认。','修改密码,更改密码',1,'2026-04-11 10:30:11'),(72,'成员-个人信息','个人中心有哪些功能？','个人中心提供：个人信息查看/编辑、项目管理、活动管理、奖项管理、简历管理、学习记录查看等功能入口。','个人中心,我的',1,'2026-04-11 10:30:11'),(75,'成员-活动','如何查看我报名的活动？','登录后进入\"个人中心\"，点击\"我的活动\"查看所有报名记录和处理状态。','我的活动,查看报名,查看我报名的活动,已报名的活动',1,'2026-04-11 10:30:11'),(78,'成员-项目','如何查看我的项目申请记录？','登录后进入\"个人中心\"，点击\"我的项目\"查看所有项目及其审核状态。','我的项目,项目记录',1,'2026-04-11 10:30:11'),(79,'成员-项目','项目申请被拒绝后可以重新申请吗？','可以，修改项目信息后可以重新提交申请。','项目被拒,重新申请',1,'2026-04-11 10:30:11'),(81,'成员-奖项','如何查看我的获奖记录？','登录后进入\"个人中心\"，点击\"我的奖项\"查看所有获奖记录及审核状态。','我的奖项,获奖记录',1,'2026-04-11 10:30:11'),(82,'成员-奖项','奖项申请被拒绝后怎么办？','可以在\"我的奖项\"页面重新编辑信息后再次提交申请。','奖项被拒,重新申请',1,'2026-04-11 10:30:11'),(83,'成员-学习','如何开始学习签到？','点击导航\"学习中心\"，在规定时间（6:00-22:00）内点击\"开始学习\"按钮进行签到。','开始学习,签到,学习签到',1,'2026-04-11 10:30:11'),(84,'成员-学习','学习时间有什么规则？','学习时间为6:00-22:00。18:00前签到为正常，18:00-19:00为迟到，19:00后为严重迟到。22:00系统自动结束学习。','学习规则,签到规则',1,'2026-04-11 10:30:11'),(85,'成员-学习','如何签退结束学习？','在学习中心点击\"签退\"按钮结束学习。21:30前签退为正常早退，21:30后为正常签退。','签退,结束学习',1,'2026-04-11 10:30:11'),(86,'成员-学习','忘记了签到怎么办？','请在下次学习时注意签到时间，系统会自动记录。目前不支持补签。','忘记签到,补签',1,'2026-04-11 10:30:11'),(87,'成员-问题反馈','如何提交问题反馈？','点击导航\"问题反馈\"，填写问题标题和详细描述后提交。管理员处理后可在列表查看状态。','提交反馈,问题反馈,提交问题',1,'2026-04-11 10:30:11'),(88,'成员-问题反馈','如何查看我提交的问题？','在问题反馈页面可以看到所有历史反馈记录及处理状态（待确认/属实/不属实）。','查看反馈,我的反馈',1,'2026-04-11 10:30:11'),(90,'管理员-新闻管理','如何修改已发布的新闻？','在新闻列表找到目标新闻，点击\"编辑\"按钮修改内容后保存。','修改新闻,编辑新闻',1,'2026-04-11 10:30:11'),(91,'管理员-新闻管理','如何删除新闻？','在新闻列表找到目标新闻，点击\"删除\"按钮确认删除。注意：已关联活动的新闻无法删除。','删除新闻',1,'2026-04-11 10:30:11'),(92,'管理员-活动管理','如何创建新活动？','点击\"活动管理\"，点击\"创建活动\"，填写活动名称、时间、地点，设置报名起止时间后保存。','创建活动,新建活动',1,'2026-04-11 10:30:11'),(93,'管理员-活动管理','如何查看活动报名情况？','在活动列表点击\"报名管理\"按钮，可查看所有报名成员及审核状态。','查看报名,报名情况',1,'2026-04-11 10:30:11'),(94,'管理员-活动管理','如何删除活动？','在活动列表找到目标活动，点击\"删除\"按钮。注意：进行中或已结束的活动无法删除。','删除活动',1,'2026-04-11 10:30:11'),(95,'管理员-项目管理','如何审核项目申请？','在项目管理页面查看\"待审核\"状态的项目，点击\"批准\"通过或\"编辑\"查看详情后处理。','审核项目,审批项目',1,'2026-04-11 10:30:11'),(96,'管理员-项目管理','项目状态有哪几种？','项目状态分为：待审核（黄色）、已通过（绿色）、已拒绝（红色）三种。','项目状态',1,'2026-04-11 10:30:11'),(97,'管理员-奖项管理','如何审核奖项申请？','在奖项管理页面查看待审核申请，点击\"通过\"或\"拒绝\"按钮处理。','审核奖项,审批奖项',1,'2026-04-11 10:30:11'),(98,'管理员-奖项管理','奖项状态有哪几种？','奖项状态分为：待审核、已通过、已拒绝三种。','奖项状态',1,'2026-04-11 10:30:11'),(99,'管理员-成员管理','如何重置成员密码？','在成员管理页面找到目标成员，点击\"重置密码\"按钮。系统会将密码重置为默认密码123456。','重置密码,忘记密码',1,'2026-04-11 10:30:11'),(100,'管理员-招新管理','如何处理招新报名？','点击\"招新管理\"，查看待处理申请，点击\"同意\"为申请者创建账号（学号即用户名，默认密码123456），或点击\"拒绝\"驳回。','处理报名,审核报名',1,'2026-04-11 10:30:11'),(101,'管理员-学习管理','如何查看学习记录？','点击\"学习管理\"，可按日期范围和成员筛选查看学习时段记录，包括开始时间、结束时间、学习时长等。','查看学习,学习记录',1,'2026-04-11 10:30:11'),(102,'管理员-学习管理','可以统计学习数据吗？','可以，学习管理页面顶部显示总学习次数、已完成次数、总时长、平均时长等统计信息。','学习统计',1,'2026-04-11 10:30:11'),(103,'管理员-问题管理','如何处理问题反馈？','点击\"问题管理\"，以三个标签页查看（属实/不属实/待确认），点击\"查看\"可更新分类、状态和处理备注。','处理问题,审核问题',1,'2026-04-11 10:30:11'),(104,'管理员-问题管理','如何删除问题反馈？','在问题列表点击\"删除\"按钮，可移除不再需要的问题记录。','删除问题',1,'2026-04-11 10:30:11'),(105,'账号问题','忘记密码怎么办？','联系管理员重置密码，重置后默认密码为123456，首次登录后请立即修改。','忘记密码,密码找回',1,'2026-04-11 10:30:11'),(106,'账号问题','默认登录密码是什么？','新账号默认密码为123456，登录后请立即修改密码。','默认密码',1,'2026-04-11 10:30:11'),(107,'账号问题','账户被锁定怎么办？','联系管理员解锁账户。','账户锁定,账号锁定,解锁',1,'2026-04-11 10:30:11'),(108,'学习规则','学习时间段是什么？','系统学习时间为每日6:00-22:00。18:00系统会强制签退（如正在学习中）。','学习时间,时段',1,'2026-04-11 10:30:11'),(109,'学习规则','签到状态如何判定？','6:00-18:00签到为正常；18:00-19:00为迟到；19:00之后为严重迟到。','签到状态',1,'2026-04-11 10:30:11'),(110,'学习规则','签退状态如何判定？','21:30前签退为早退；21:30后签退为正常；22:00系统自动结束学习。','签退状态',1,'2026-04-11 10:30:11');
