LOCK TABLES `ai_message` WRITE;
/*!40000 ALTER TABLE `ai_message` DISABLE KEYS */;
INSERT INTO `ai_message` VALUES (1,1,'user','如何报名参加活动？','2026-03-24 17:04:41'),(2,1,'assistant','进入活动列表 -> 选择您感兴趣的活动 -> 点击\"报名\"按钮 -> 根据提示完成报名流程（请确保您在活动规定的报名时间内操作）。','2026-03-24 17:04:44'),(3,2,'user','如何提交奖项申请？','2026-03-24 17:13:04'),(4,2,'assistant','请按照以下步骤提交奖项申请：\n\n1. 登录软件小组管理系统。\n2. 进入\"我的奖项\"页面。\n3. 点击\"提交奖项\"按钮。\n4. 填写奖项申请表单，确保所有信息准确无误。\n5. 上传相关的证书或证明文件。\n6. 提交申请。\n\n完成以上步骤后，您的奖项申请将被提交至审核人员进行审核。','2026-03-24 17:13:09'),(5,3,'user','如何报名参加活动？','2026-03-24 17:57:44'),(6,3,'assistant','进入活动列表 -> 选择您感兴趣的活动 -> 点击\"报名\"按钮 -> 根据提示完成报名信息的填写 -> 提交报名（请确保在活动规定的报名时间内操作）。','2026-03-24 17:57:46'),(7,3,'user','如何编辑个人简历？','2026-03-24 17:58:00'),(8,3,'assistant','在黄山学院软件小组管理系统中编辑个人简历的步骤如下：\n\n1. 登录系统：首先，使用您的账号和密码登录软件小组管理系统。\n\n2. 进入个人中心：登录后，通常在页面的右上角会有一个“个人中心”或“我的”链接，点击进入。\n\n3. 查找简历编辑选项：在个人中心页面，寻找“简历管理”、“编辑简历”或类似的选项。\n\n4. 填写或更新简历信息：在简历编辑页面，您可以添加或修改个人信息，包括但不限于姓名、联系方式、教育背景、技能、项目经验、获奖情况等。\n\n5. 保存或提交简历：填写完毕后，检查信息无误，然后保存您的简历。如果系统支持在线提交，您可以选择提交给管理员或相关负责人。\n\n6. 确认提交：提交后，系统可能会给出提交成功的提示。如果需要进一步的确认或反馈，按照系统提示操作。\n\n请注意，具体的操作步骤可能会根据软件小组管理系统的实际设计有所不同，如果在操作过程中遇到困难，可以查看系统的帮助文档或联系系统管理员获取帮助。','2026-03-24 17:58:07'),(9,3,'user','现在几点了','2026-03-24 17:58:19'),(10,3,'assistant','很抱歉，作为AI助手，我无法提供实时时间信息。请查看您的设备上的时间显示以获取当前时间。如果您有其他关于软件小组管理系统的问题，我会很乐意帮助您解答。','2026-03-24 17:58:21'),(11,4,'user','如何登录系统？','2026-03-24 20:13:15'),(12,4,'assistant','要登录黄山学院软件小组管理系统，请按照以下步骤操作：\n\n1. 打开您的网络浏览器。\n2. 在地址栏中输入系统提供的网址或访问链接。\n3. 在登录页面上，输入您的账号信息，通常是您的学号或用户ID。\n4. 输入您的密码。\n5. 点击登录按钮。\n\n如果您是首次登录，可能需要进行一些初始设置，比如修改密码或确认个人信息。如果遇到登录问题，请检查您的网络连接，确认账号和密码是否正确，或联系系统管理员获取帮助。','2026-03-24 20:13:19'),(13,5,'user','如何创建项目？','2026-03-24 20:42:58'),(14,5,'assistant','登录系统后，进入\"我的项目\"页面，点击\"创建项目\"按钮，然后按照提示填写项目相关信息，包括项目名称、描述、目标等，最后提交项目等待审核即可。','2026-03-24 20:43:01'),(15,6,'user','忘记了密码怎么办？','2026-03-24 21:50:00'),(16,6,'assistant','AI服务错误: Access token invalid or no longer valid','2026-03-24 21:50:01'),(17,7,'user','如何编辑个人简历？','2026-03-24 22:18:47'),(18,7,'assistant','在黄山学院软件小组管理系统中编辑个人简历的步骤如下：\n\n1. 登录系统：首先，使用您的账号和密码登录软件小组管理系统。\n\n2. 进入个人中心：登录后，通常在首页的右上角会有“个人中心”或“我的”之类的链接，点击进入。\n\n3. 查找简历编辑选项：在个人中心页面，寻找“简历管理”或“编辑简历”的选项。这个选项可能位于页面的侧边栏或者页面的主体部分。\n\n4. 开始编辑简历：点击“编辑简历”后，系统会引导您进入简历编辑页面。在这里，您可以添加或修改您的个人信息、教育背景、技能、项目经验、获奖情况等。\n\n5. 填写或更新信息：根据提示填写或更新您的简历信息。请确保所有信息准确无误，并且尽可能详细地展示您的技能和经验。\n\n6. 保存或提交简历：编辑完成后，检查信息无误，然后保存您的简历。如果系统支持在线提交，您可以选择提交给管理员或相关负责人。\n\n7. 提交后等待审核：提交简历后，可能需要等待系统管理员或负责人的审核。审核通过后，您的简历将被正式更新。\n\n请注意','2026-03-24 22:18:56'),(19,8,'user','如何报名参加活动？','2026-03-25 13:32:57'),(20,8,'assistant','您好！我是AI助手。\n\n我可以帮您解答以下问题：\n- 如何发布新闻\n- 如何审核奖项申请\n- 如何创建活动\n- 如何处理招新报名\n- 如何管理成员\n- 项目管理相关问题\n\n请告诉我您想了解的具体问题。','2026-03-25 13:32:57'),(21,8,'user','如何编辑个人简历？','2026-03-25 13:33:04'),(22,8,'assistant','您好！我是AI助手。\n\n我可以帮您解答以下问题：\n- 如何发布新闻\n- 如何审核奖项申请\n- 如何创建活动\n- 如何处理招新报名\n- 如何管理成员\n- 项目管理相关问题\n\n请告诉我您想了解的具体问题。','2026-03-25 13:33:04'),(23,9,'user','如何创建活动？','2026-03-25 13:33:34'),(24,9,'assistant','创建新活动的步骤：\n1. 进入\'活动管理\'页面\n2. 点击\'创建活动\'\n3. 填写活动名称、时间、地点\n4. 设置报名起止时间\n5. 点击保存','2026-03-25 13:33:34'),(25,9,'user','如何重置成员密码？','2026-03-25 13:33:38'),(26,9,'assistant','您好！我是AI助手。\n\n我可以帮您解答以下问题：\n- 如何发布新闻\n- 如何审核奖项申请\n- 如何创建活动\n- 如何处理招新报名\n- 如何管理成员\n- 项目管理相关问题\n\n请告诉我您想了解的具体问题。','2026-03-25 13:33:38'),(27,9,'user','如何创建活动？','2026-03-25 13:33:45'),(28,9,'assistant','创建新活动的步骤：\n1. 进入\'活动管理\'页面\n2. 点击\'创建活动\'\n3. 填写活动名称、时间、地点\n4. 设置报名起止时间\n5. 点击保存','2026-03-25 13:33:45'),(29,9,'user','如何重置成员密码？','2026-03-25 13:33:49'),(30,9,'assistant','您好！我是AI助手。\n\n我可以帮您解答以下问题：\n- 如何发布新闻\n- 如何审核奖项申请\n- 如何创建活动\n- 如何处理招新报名\n- 如何管理成员\n- 项目管理相关问题\n\n请告诉我您想了解的具体问题。','2026-03-25 13:33:49'),(31,9,'user','如何发布新闻？','2026-03-25 13:33:53'),(32,9,'assistant','作为管理员，您可以这样管理新闻：\n1. 进入\'新闻管理\'页面\n2. 点击\'发布新闻\'创建新新闻\n3. 填写标题、内容、选择类型（获奖/活动/通知）\n4. 点击保存发布\n如有其他问题，请联系管理员。','2026-03-25 13:33:53'),(33,10,'user','如何处理招新报名？','2026-03-25 16:15:37'),(34,10,'assistant','处理招新报名的步骤：\n1. 进入\'招新管理\'页面\n2. 查看待处理申请\n3. 点击\'审核\'查看详情\n4. 点击\'同意\'创建账号或\'拒绝\'驳回申请','2026-03-25 16:15:37'),(35,10,'user','如何重置成员密码？','2026-03-25 16:15:40'),(36,10,'assistant','您好！我是AI助手。\n\n我可以帮您解答以下问题：\n- 如何发布新闻\n- 如何审核奖项申请\n- 如何创建活动\n- 如何处理招新报名\n- 如何管理成员\n- 项目管理相关问题\n\n请告诉我您想了解的具体问题。','2026-03-25 16:15:40'),(37,11,'user','忘记了密码怎么办？','2026-03-25 16:53:41'),(38,11,'assistant','如果您忘记了黄山学院软件小组管理系统的密码，请按照以下步骤操作：\n\n1. 打开软件小组管理系统的登录页面。\n2. 找到“忘记密码？”或“找回密码”链接，点击进入。\n3. 输入您注册时使用的邮箱地址或用户名。\n4. 系统将发送一封包含密码重置链接的邮件到您的注册邮箱。\n5. 检查您的邮箱，点击邮件中的链接按照提示设置新的密码。\n6. 使用新设置的密码登录系统。\n\n如果在找回密码的过程中遇到任何问题，可以联系系统管理员获取帮助。','2026-03-25 16:53:47'),(39,12,'user','如何修改个人资料','2026-03-25 17:06:18'),(40,12,'assistant','要修改个人资料，请按照以下步骤操作：\n\n1. 登录软件小组管理系统。\n2. 进入个人中心或用户设置页面。\n3. 找到“编辑资料”或“修改资料”选项。\n4. 点击后，你可以更新你的个人信息，如姓名、邮箱、电话号码等。\n5. 修改完毕后，保存更改。\n\n如果系统有特定的流程或界面，请根据系统内的提示进行操作。如果遇到任何问题，可以联系系统管理员获取帮助。','2026-03-25 17:06:22'),(41,12,'user','如何报名参加活动？','2026-03-25 17:09:34'),(42,12,'assistant','进入活动列表 -> 选择您感兴趣的活动 -> 点击\"报名\"按钮 -> 根据提示完成报名流程（请确保在活动规定的报名时间内操作）。','2026-03-25 17:09:35'),(43,12,'user','如何提交奖项申请？','2026-03-25 17:10:24'),(44,12,'assistant','请按照以下步骤提交奖项申请：\n\n1. 登录软件小组管理系统。\n2. 进入\"我的奖项\"页面。\n3. 点击\"提交奖项\"按钮。\n4. 填写奖项申请表单，确保所有信息准确无误。\n5. 上传相关的证书或证明文件。\n6. 提交申请。\n\n完成以上步骤后，您的奖项申请将被提交至审核人员进行审核。','2026-03-25 17:10:29'),(45,13,'user','如何登录系统？','2026-03-26 17:02:20'),(46,13,'assistant','要登录黄山学院软件小组管理系统，请按照以下步骤操作：\n\n1. 打开浏览器，输入系统网址或在校园网内找到系统链接。\n2. 在登录页面，输入您的账号（通常是学号或工号）。\n3. 输入您的密码。\n4. 点击登录按钮。\n\n如果系统有额外的安全验证，如验证码或手机短信验证，请按照页面提示完成验证步骤。\n\n如果您忘记密码或遇到登录问题，请使用系统提供的“忘记密码”或“联系管理员”功能来重置密码或获取帮助。','2026-03-26 17:02:24'),(47,14,'user','如何重置成员密码？','2026-03-26 17:09:48'),(48,14,'assistant','在软件小组管理系统中，重置成员密码通常需要管理员权限。以下是重置密码的一般步骤：\n\n1. 登录系统：首先，您需要以管理员身份登录到软件小组管理系统。\n\n2. 访问成员管理：在系统界面中找到“成员管理”或“用户管理”模块。\n\n3. 选择成员：在成员列表中找到需要重置密码的成员。\n\n4. 重置密码：点击该成员的用户名或操作栏中的“重置密码”选项。系统可能会要求您输入新的密码或自动生成一个密码。\n\n5. 确认操作：确认密码已成功更新，并确保新密码已发送给该成员（如果系统支持通过邮件发送密码的话）。\n\n6. 通知成员：最后，通知该成员他们的密码已经重置，并提供新的密码信息。\n\n请注意，具体的操作步骤可能会根据您使用的软件小组管理系统的版本和定制情况有所不同。如果您在操作过程中遇到困难，可以查看系统的帮助文档或联系系统的技术支持获取帮助。','2026-03-26 17:09:56'),(49,15,'user','如何登录系统？','2026-03-27 15:38:23'),(50,15,'assistant','MiniMax服务错误: your current token plan not support model, abab6.5s-chat','2026-03-27 15:38:24'),(51,16,'user','忘记了密码怎么办？','2026-03-27 17:52:52'),(52,16,'assistant','MiniMax服务错误: your current token plan not support model, abab6.5s-chat','2026-03-27 17:52:53'),(53,17,'user','忘记了密码怎么办？','2026-03-27 17:55:28'),(54,17,'assistant','MiniMax服务错误: your current token plan not support model, abab6.5-chat','2026-03-27 17:55:29'),(55,18,'user','如何登录系统？','2026-03-27 17:58:24'),(56,18,'assistant','MiniMax服务错误: invalid params, code: 2013, msg: invalid params, unknown model \'abab6.7-chat\'','2026-03-27 17:58:25'),(57,19,'user','忘记了密码怎么办？','2026-03-27 17:59:19'),(58,19,'assistant','MiniMax服务错误: invalid params, code: 2013, msg: invalid params, unknown model \'abab6.7-chat\'','2026-03-27 17:59:20'),(59,19,'user','如何提交招新报名？','2026-03-27 17:59:22'),(60,19,'assistant','MiniMax服务错误: invalid params, code: 2013, msg: invalid params, unknown model \'abab6.7-chat\'','2026-03-27 17:59:22'),(61,19,'user','有哪些新闻和活动？','2026-03-27 17:59:24'),(62,19,'assistant','MiniMax服务错误: invalid params, code: 2013, msg: invalid params, unknown model \'abab6.7-chat\'','2026-03-27 17:59:24'),(63,20,'user','有哪些新闻和活动？','2026-03-27 18:01:53'),(64,20,'assistant','MiniMax服务错误: invalid params, code: 2013, msg: invalid params, unknown model \'minimax-2.7\'','2026-03-27 18:01:54'),(65,21,'user','有哪些新闻和活动？','2026-03-27 18:03:32'),(66,21,'assistant','MiniMax服务错误: invalid params, code: 2013, msg: invalid params, unknown model \'minimax-2.7\'','2026-03-27 18:03:33'),(67,22,'user','忘记了密码怎么办？','2026-03-27 18:05:42'),(68,22,'assistant','MiniMax服务错误: invalid params, code: 2013, msg: invalid params, unknown model \'minimax m2.7\'','2026-03-27 18:05:43'),(69,23,'user','如何登录系统？','2026-03-27 18:06:04'),(70,23,'assistant','MiniMax服务错误: invalid params, code: 2013, msg: invalid params, unknown model \'minimax m2.7\'','2026-03-27 18:06:05'),(71,24,'user','如何登录系统？','2026-03-27 18:10:07'),(72,24,'assistant','MiniMax服务错误: invalid params, code: 2013, msg: 