--
-- Table structure for table `problem_management`
--

DROP TABLE IF EXISTS `problem_management`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `problem_management` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '问题ID',
  `report_id` int NOT NULL COMMENT '关联的问题反馈ID',
  `category` enum('VERIFIED','INVALID','UNVERIFIED') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'UNVERIFIED' COMMENT '分类：VERIFIED-属实，INVALID-不属实，UNVERIFIED-待确认',
  `status` enum('PENDING','SOLVING','SOLVED') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'PENDING' COMMENT '处理状态：PENDING-待修改，SOLVING-正在修改，SOLVED-已修改（仅属实问题有状态）',
  `admin_comment` text COLLATE utf8mb4_unicode_ci COMMENT '管理员备注/回复',
  `handled_by` int DEFAULT NULL COMMENT '处理人ID',
  `handled_at` datetime DEFAULT NULL COMMENT '处理时间',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_report_id` (`report_id`),
  KEY `idx_category` (`category`),
